qry:select.qry:xquery:
for $r in sql(' FROMROW {%=#PAGEDATA:@fromrow%} MAXSIZE {%=#PAGEDATA:@qpagesize%}
SELECT p.d_ape_y_nom, pe.e_numero_legajo, p.te_celular, p.d_email, e.d_empresa, u.d_ubicacion, u.c_ubicacion, cc.d_centro_costo, pu.d_puesto, u.n_pais, u.n_area, u.n_telefono, u.d_calle, u.e_numero, u.e_piso, u.d_departamento, u.c_postal, p.oi_foto, p.oi_usuario_sistema, pe.c_nro_interno
FROM PER01_PERSONAL as p, PER02_PERSONAL_EMP as pe, ORG03_EMPRESAS as e, ORG03_UBICACIONES as u, ORG08_CS_COSTO AS cc, ORG04_PUESTOS AS pu
JOIN p.oi_personal INNER pe.oi_personal, pe.oi_empresa INNER e.oi_empresa, pe.oi_ubicacion LEFT OUTER u.oi_ubicacion, pe.oi_ctro_costo_ult LEFT OUTER cc.oi_centro_costo, pe.oi_puesto_ult LEFT OUTER pu.oi_puesto
WHERE pe.oi_indic_activo = 1 {%? (#PARAM:@search != '') {% AND ( CONTAIN(p.d_ape_y_nom, {#PARAM:@search}) OR CONTAIN(e.d_empresa, {#PARAM:@search}) OR CONTAIN(u.c_ubicacion + \'-\' + u.d_ubicacion, {#PARAM:@search}) OR CONTAIN(cc.d_centro_costo, {#PARAM:@search}) OR CONTAIN(pu.d_puesto, {#PARAM:@search}) OR CONTAIN(u.d_calle, {#PARAM:@search}) OR CONTAIN(u.d_departamento, {#PARAM:@search}) ) %} {% %} %} {%? (#PARAM:@oi_personal != '') {% AND p.oi_personal = {#PARAM:@oi_personal} %} {% %} %}
{%? (#PARAM:@search = '' AND #PARAM:@oi_personal = '') {% AND 1 = 2 %} {% %} %}
ORDER BY d_ape_y_nom ASC
')/ROWS/ROW

html:xslt.xsl:template:
			var pageSize = 10;

			function OnLoad() {
				var objTemp;

				//Setea el pagesize
				objTemp = document.getElementById("hidPS");
				if (objTemp != null)
					if (objTemp.value != "") pageSize = objTemp.value;

				document.getElementById("txtSer").focus();

			}

			function SplitStruct() {
				var objTemp;
				var arrEst, strEst;
				var strResult = "";
				var x, y;
				var maxCadenas = 6;

				objTemp = document.getElementById("estruc");
				if (objTemp.value != "") {
					arrEst = objTemp.value.split("+");

					if (Compare(arrEst.length, maxCadenas) == -1) {
						alert("No se puden superar las " + maxCadenas + " cadenas de búsqueda en el campo Estructura. Las cadenas por encima del máximo se omitirán");
					}

					for (x = 0; x != arrEst.length; x++) {
						strEst = jsTrim(arrEst[x]);

						strResult = strResult + "{#CHAR.AMP#}es" + (x + 1) + "=" + encodeURIComponent(strEst);

						strSep = "(M)";
					}

				}

				return strResult;
			}


			function GetRows(pFrom, pPageSize) {
				var dir;
				var params = "";
				var temp;
				var objTemp;

				dir = "../../../ReportViewer.aspx?";
				dir = dir + "report={#PROXY.APP#}.NucleusRH.Base.Personal.BuscadorLegajos.GEN.GADGET";

 				objTemp = document.getElementById("txtSer");
				if (objTemp.value != "") params = params + "{#CHAR.AMP#}search=" + encodeURIComponent(objTemp.value);

				//Agrega el paginado
				params = params + "{#CHAR.AMP#}fromrow=" + pFrom;
				params = params + "{#CHAR.AMP#}pagesize=" + pPageSize;

 				if (params != "")
					document.location = dir + params;

				return;
			}

			function SearchKeyPress(code) {
				if (code == 13) Search();
			}

			function Search() {
				GetRows(0, pageSize);
				return;
			}

			function tdBotonPrev() {
				var objTemp;
				var paFrom = 0;

 				objTemp = document.getElementById("hidFromRow");
				if (objTemp.value != "") paFrom = objTemp.value;

				paFrom = paFrom - pageSize;

				GetRows(paFrom, pageSize);
				return;
			}

			function tdBotonNext() {
				var objTemp;
				var paFrom = 0;

 				objTemp = document.getElementById("hidFromRow");
				if (objTemp.value != "") paFrom = objTemp.value; 

				paFrom = parseInt(paFrom, 10) + parseInt(pageSize, 10);

				GetRows(paFrom, pageSize);
				return;
			}

			function ChangeStyleBut2(pobj, pType) {
				if (pType == "OVER")
					pobj.className = "boton2_o";
				else
					pobj.className = "boton2_n";
			}

			function jsTrim (pTarget) {
 				return pTarget.replace(/^\s*|\s*$/g,"");
			}

			function Replace(strin, strfnd, strrpl) {
				var strout="", lastpos;

				for (lastpos=0, pos=strin.indexOf(strfnd); pos!=-1; lastpos=pos+strfnd.length, pos=strin.indexOf(strfnd,lastpos))
				{                
					strout+=strin.substr(lastpos,pos-lastpos);
					strout+=strrpl;
				} 		
				strout+=strin.substr(lastpos);

				return strout;
			}

			.ResultRow {
			height:110px;
		}

	.ResultRow TD {
  		border-bottom-width: 1px;
  		border-bottom-style: solid;
  		border-bottom-color: #C8C8C8;

  		border-top-width: 1px;
  		border-top-style: solid;
  		border-top-color: #C8C8C8;

  		padding-top: 5px;
		}
